function generateTimeSeriesData(months = 24) {
    const data = [];
    const now = new Date();
    // Seed-based deterministic generation (no Math.random) for consistency
    function seededValue(base, growth, progress, i, phase) {
        const trend = base + base * growth * progress;
        const seasonal = base * 0.15 * Math.sin(2 * Math.PI * (i + phase) / 12);
        const micro = base * 0.05 * Math.cos(i * 1.7 + phase);
        return Math.max(1, Math.round(trend + seasonal + micro));
    }
    for(let i = months - 1; i >= 0; i--){
        const date = new Date(now);
        date.setMonth(date.getMonth() - i);
        const progress = (months - i) / months;
        data.push({
            date: date.toISOString().slice(0, 7),
            ransomware: seededValue(120, 1.5, progress, i, 0),
            apt: seededValue(45, 1.1, progress, i, 1),
            phishing: seededValue(300, 0.8, progress, i, 2),
            supplyChain: seededValue(20, 2.5, progress, i, 3),
            zeroDay: seededValue(8, 1.8, progress, i, 4),
            ddos: seededValue(200, 0.5, progress, i, 5),
            cryptojacking: seededValue(50, -0.3, progress, i, 6),
            insiderThreat: seededValue(30, 0.6, progress, i, 7),
            iotExploit: seededValue(15, 2.8, progress, i, 8),
            aiPowered: seededValue(5, 4.0, progress, i, 9)
        });
    }
    return data;
}
function generatePredictions() {
    // Derive predictions from time-series trends
    const series = generateTimeSeriesData(24);
    const recent6 = series.slice(-6);
    const early6 = series.slice(0, 6);
    function derive(field, label, recommendation) {
        const recentAvg = recent6.reduce((s, p)=>s + p[field], 0) / 6;
        const earlyAvg = early6.reduce((s, p)=>s + p[field], 0) / 6;
        const changePct = earlyAvg > 0 ? Math.round((recentAvg - earlyAvg) / earlyAvg * 100) : 0;
        const trend = changePct > 20 ? "rising" : changePct < -10 ? "declining" : "stable";
        const riskLevel = changePct > 150 ? "critical" : changePct > 50 ? "high" : changePct > 10 ? "medium" : "low";
        const confidence = Math.min(0.98, Math.max(0.6, 0.85 + (1 - Math.abs(changePct) / 500) * 0.1));
        return {
            category: label,
            currentTrend: trend,
            predictedChange: changePct,
            confidence: Math.round(confidence * 100) / 100,
            nextMonthEstimate: Math.round(recentAvg * (1 + changePct / 600)),
            riskLevel,
            recommendation
        };
    }
    return [
        derive("aiPowered", "AI-Powered Attacks", "Deploy AI-based anomaly detection. Traditional signature-based defenses are insufficient against polymorphic AI-generated payloads."),
        derive("supplyChain", "Supply Chain Attacks", "Implement SBOM analysis, enforce zero-trust for third-party integrations, and conduct continuous dependency auditing."),
        derive("ransomware", "Ransomware", "Maintain offline backups, deploy EDR, and implement network segmentation to limit lateral movement."),
        derive("iotExploit", "IoT Exploits", "Enforce device inventory management, segment IoT networks, and mandate firmware update policies."),
        derive("apt", "APT Campaigns", "Enhance threat intelligence sharing, deploy deception technologies, and conduct quarterly red team exercises."),
        derive("phishing", "Phishing", "Implement DMARC/DKIM/SPF, deploy browser isolation, and conduct monthly phishing simulations."),
        derive("ddos", "DDoS", "Use multi-layer DDoS mitigation, implement rate limiting, and maintain upstream ISP scrubbing centers."),
        derive("cryptojacking", "Cryptojacking", "Monitor CPU/GPU usage anomalies, deploy browser extensions to block mining scripts, and audit cloud workloads.")
    ].sort((a, b)=>b.predictedChange - a.predictedChange);
}
