function generateSeverityDistribution() {
    // Derived from current attack patterns
    const patterns = generateAttackPatterns();
    const counts = {
        Critical: 0,
        High: 0,
        Medium: 0,
        Low: 0
    };
    for (const p of patterns){
        if (p.severity === "critical") counts.Critical++;
        else if (p.severity === "high") counts.High++;
        else if (p.severity === "medium") counts.Medium++;
        else counts.Low++;
    }
    const total = Object.values(counts).reduce((a, b)=>a + b, 0) || 1;
    return [
        {
            name: "Critical",
            value: Math.round(counts.Critical / total * 100),
            color: "#ef4444"
        },
        {
            name: "High",
            value: Math.round(counts.High / total * 100),
            color: "#f97316"
        },
        {
            name: "Medium",
            value: Math.round(counts.Medium / total * 100),
            color: "#eab308"
        },
        {
            name: "Low",
            value: Math.round(counts.Low / total * 100),
            color: "#22c55e"
        }
    ];
}
function generateMitreTacticData() {
    // Derived from techniques referenced in attack patterns
    const patterns = generateAttackPatterns();
    const tacticCounts = new Map();
    for (const p of patterns){
        for (const tactic of p.mitreTactics){
            tacticCounts.set(tactic, (tacticCounts.get(tactic) || 0) + p.frequency);
        }
    }
    const total = Array.from(tacticCounts.values()).reduce((a, b)=>a + b, 0) || 1;
    return Array.from(tacticCounts.entries()).map(([tactic, count])=>({
            tactic,
            count,
            percentage: Math.round(count / total * 1000) / 10
        })).sort((a, b)=>b.count - a.count);
}
function generateSectorRiskData() {
    // Derived from attack pattern target sectors
    const patterns = generateAttackPatterns();
    const sectorData = new Map();
    const severityWeight = {
        critical: 4,
        high: 3,
        medium: 2,
        low: 1
    };
    for (const p of patterns){
        for (const sector of p.targetSectors){
            const existing = sectorData.get(sector) || {
                incidents: 0,
                riskTotal: 0,
                count: 0
            };
            existing.incidents += Math.round(p.frequency / p.targetSectors.length);
            existing.riskTotal += severityWeight[p.severity] * p.confidence * 25;
            existing.count++;
            sectorData.set(sector, existing);
        }
    }
    return Array.from(sectorData.entries()).map(([sector, data])=>{
        const avgRisk = data.riskTotal / data.count;
        const trend = avgRisk > 70 ? "rising" : avgRisk > 40 ? "stable" : "declining";
        return {
            sector,
            riskScore: Math.min(100, Math.round(avgRisk)),
            incidents: data.incidents,
            trend,
            vulnerabilities: Math.round(data.incidents * 0.22)
        };
    }).sort((a, b)=>b.riskScore - a.riskScore);
}
